import{_ as e,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o as d,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"User Rate Limits","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Safety/user-rate-limits.md","filePath":"fa/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),r={name:"fa/Safety/user-rate-limits.md"};function o(p,t,n,u,c,h){return d(),l("div",null,[...t[0]||(t[0]=[s('<h1 id="user-rate-limits" tabindex="-1">User Rate Limits <a class="header-anchor" href="#user-rate-limits" aria-label="Permalink to &quot;User Rate Limits&quot;">​</a></h1><p>User rate limits کنترل می‌کند regular users یا visitors هر چند وقت یک‌بار می‌توانند از homepage files upload کنند. این کار از abuse شدن public upload pages جلوگیری می‌کند.</p><p>این feature فقط homepage uploads را تحت تأثیر قرار می‌دهد. Admin uploads و uploads انجام‌شده با API Tokens محدود به user rate limits نیستند.</p><h2 id="کجا-configure-کنیم" tabindex="-1">کجا Configure کنیم <a class="header-anchor" href="#کجا-configure-کنیم" aria-label="Permalink to &quot;کجا Configure کنیم&quot;">​</a></h2><p>admin panel را باز کنید و بروید به:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+e+'" alt="User rate limit settings" loading="lazy"></p><h2 id="enable-کردن-rate-limits" tabindex="-1">Enable کردن Rate Limits <a class="header-anchor" href="#enable-کردن-rate-limits" aria-label="Permalink to &quot;Enable کردن Rate Limits&quot;">​</a></h2><p>بعد از روشن شدن <code>Enable Rate Limits</code>، ImgBed recent uploads را بر اساس uploader IP address track می‌کند.</p><p>Default values:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>upload records تا چه فاصله زمانی عقب‌تر شمرده شوند.</td></tr><tr><td>Max file count</td><td>20</td><td>بیشترین تعداد files مجاز در detection window.</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>بیشترین اندازه یک file.</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>بیشترین total upload size در detection window.</td></tr></tbody></table><p>مثلاً با window برابر 1.5 hours، 20 files، 20 MB برای هر file و 200 MB total، upload از همان IP وقتی هر کدام از limits رد شود blocked خواهد شد.</p><h2 id="excluding-file-types" tabindex="-1">Excluding File Types <a class="header-anchor" href="#excluding-file-types" aria-label="Permalink to &quot;Excluding File Types&quot;">​</a></h2><p><code>Excluded upload file types</code> جلوی upload شدن دسته‌های انتخابی file توسط regular users یا visitors را می‌گیرد.</p><p>دسته‌های موجود:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif و image files مشابه</td></tr><tr><td>Videos</td><td>mp4, webm, mov و video files مشابه</td></tr><tr><td>Audio</td><td>mp3, flac, wav و audio files مشابه</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx و document files مشابه</td></tr><tr><td>Other</td><td>files خارج از دسته‌های بالا، مثل zip, rar, exe, apk</td></tr></tbody></table><p>به‌صورت پیش‌فرض هیچ type انتخاب نشده، یعنی allowed است.</p><p>با click روی یک type، highlight می‌شود؛ یعنی آن type blocked است.</p><p>اگر <code>Other</code> انتخاب شود، visitors که zip یا rar upload می‌کنند blocked می‌شوند و پیام unsupported file type می‌بینند.</p><h2 id="block-messages" tabindex="-1">Block Messages <a class="header-anchor" href="#block-messages" aria-label="Permalink to &quot;Block Messages&quot;">​</a></h2><p>وقتی limit فعال شود، users پیام متناظر می‌بینند:</p><p><img src="'+a+'" alt="Too frequent upload message" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Message Meaning</th></tr></thead><tbody><tr><td>Single file too large</td><td>file خیلی بزرگ است و باید قبل از upload فشرده شود.</td></tr><tr><td>File type blocked</td><td>این file type پشتیبانی نمی‌شود. آن را حذف کنید و دوباره تلاش کنید.</td></tr><tr><td>Uploads too frequent</td><td>recent uploads بیش از حد frequent است و retry time نمایش داده می‌شود.</td></tr><tr><td>Total size too high</td><td>recent total upload size زیاد است و retry time نمایش داده می‌شود.</td></tr></tbody></table><h2 id="چه-زمانی-enable-کنیم" tabindex="-1">چه زمانی Enable کنیم <a class="header-anchor" href="#چه-زمانی-enable-کنیم" aria-label="Permalink to &quot;چه زمانی Enable کنیم&quot;">​</a></h2><p>اگر upload homepage شما public accessible است، user rate limits را enable کنید.</p><p>دلایل رایج:</p><ul><li>نگران scripted bulk uploads هستید.</li><li>می‌خواهید visitor uploads بزرگ را محدود کنید.</li><li>می‌خواهید regular users فقط images upload کنند، نه archives یا installers.</li><li>می‌خواهید public upload باز بماند اما resource usage کنترل شود.</li></ul><p>اگر site فقط برای خودتان است، یا فقط administrators upload می‌کنند، می‌توانید این گزینه را disabled بگذارید.</p>',28)])])}const f=i(r,[["render",o]]);export{g as __pageData,f as default};
